        max_avg = grp['mean'].max()
        top = grp[grp['mean'] == max_avg]
        # prepare details
        details = {}
        top_refs = []
        for _, row in top.iterrows():
            br = row['business_ref']
            top_refs.append(br)
            details[br] = {"count": int(row['count']), "avg_rating": float(round(row['mean'],4))}
        out = {"top_business_refs": top_refs, "details": details}

print("__RESULT__:")
print(json.dumps(out))"}

